mapper.select:
SELECT * FROM (
    SELECT INNER_QRY.*, ROWNUM AS RNUM FROM (
        SELECT
            h.TRAN_SEQ       AS tranSeq,
            h.TRAN_ID        AS tranId,
            h.TRAN_TYPE      AS tranType,
            h.TRAN_NAME      AS tranName,
            h.TRAN_TIME      AS tranTime,
            h.TRAN_RESULT    AS tranResult
        FROM FWK_TRANS_DATA_HIS h
        WHERE h.TRAN_SEQ = #{tranSeq}


    ) INNER_QRY
    WHERE ROWNUM <= #{endRow}
)
WHERE RNUM > #{offset}

SELECT COUNT(*)
FROM FWK_TRANS_DATA_HIS h
WHERE h.TRAN_SEQ = #{tranSeq}
